const today = new Date().toISOString().split('T')[0];
const overdueItems = [];

for (const item of items) {
  const row = item.json;

  if (row.Status === 'Unpaid' && row.DueDate) {
    const dueDate = row.DueDate.split('T')[0];

    if (dueDate < today) {
      row.daysOverdue = Math.floor(
        (new Date(today) - new Date(dueDate)) / (1000 * 60 * 60 * 24)
      );

      // Don't send reminders on weekends
      const dayOfWeek = new Date().getDay();
      if (dayOfWeek >= 1 && dayOfWeek <= 5) {
        overdueItems.push(item);
      }
    }
  }
}

return overdueItems;
